const raw = $input.first().json;

const item = {
  id:                 raw.id,
  "Item Name":        raw.property_item_name,
  "Post Type":        raw.property_post_type,
  "Template Counter": raw.property_template_counter,
  "Details Type":     raw.property_details_type,
  "Condition":        raw.property_condition,
  "Price":            raw.property_price,
  "Hero Line":        raw.property_hero_line,
  "Details String":   raw.property_details_string,
  "Image 1":          raw.property_image_1,
  "Image 2":          raw.property_image_2,
  "Image 3":          raw.property_image_3,
  "Image 4":          raw.property_image_4,
};

// ── Template selection (round-robin) ──────────────────────────────
const postType = (item["Post Type"] || "A").toString().trim().toUpperCase();
const pool = registry.pools[postType] || registry.pools["A"];

const staticData = $getWorkflowStaticData('global');
const counterKey = `templateCounter_${postType}`;
const counter = staticData[counterKey] ?? 0;
const templateId = pool[counter % pool.length];
staticData[counterKey] = counter + 1;           // persists between runs
const nextCounter = staticData[counterKey];      // for Notion write-back audit

const layerMap = registry.templates[templateId].layers;

// ── Details string composer (five-branch switch) ──────────────────
const detailsType = item["Details Type"] || "single_item";
const condition = item["Condition"] || "";
const price = item["Price"]
  ? `PHP${Number(item["Price"]).toLocaleString()}`
  : "";
let detailsString = "";
switch (detailsType) {
  case "single_item":
    detailsString = [condition, price].filter(Boolean).join(" · ");
    break;
  case "multi_item":
    detailsString = "Multiple pieces · DM for prices";
    break;
  case "price_range":
    detailsString = price ? `Starting ${price}` : "Starting price — DM to ask";
    break;
  case "category_drop":
    detailsString = "Fresh arrivals · Stocks vary";
    break;
  case "arrival_teaser":
    detailsString = "Sorting now · Watch this page";
    break;
}

// ── Image URL extractor (handles Notion file array format) ────────
function extractImageUrl(field) {
  if (!field) return "";

  // Plain string
  if (typeof field === "string") {
    return field.startsWith("http") ? field : "";
  }

  // Array — n8n Notion gives an array with the URL string at [0]
  if (Array.isArray(field) && field.length > 0) {
    const f = field[0];
    if (typeof f === "string") {
      return f.startsWith("http") ? f : ""; // ← this line was missing
    }
    return f?.url || f?.file?.url || f?.external?.url || "";
  }

  // Single object
  if (typeof field === "object") {
    return field.url || field.file?.url || field.external?.url || "";
  }

  return "";
}
const imageUrls = ["Image 1", "Image 2", "Image 3", "Image 4"]
  .map((f) => extractImageUrl(item[f]))
  .filter((u) => u.length > 0);
// TEMPORARY DEBUG — remove after
// console.log("Image 1 raw:", JSON.stringify(item["Image 1"]));
// console.log("Extracted URLs:", JSON.stringify(imageUrls));

// ── Build Templated layers payload ────────────────────────────────
const layers = {};
if (layerMap.itemname && item["Item Name"]) {
  layers[layerMap.itemname] = { text: item["Item Name"] };
}
if (layerMap.hero && item["Hero Line"]) {
  layers[layerMap.hero] = { text: item["Hero Line"] };
}
if (layerMap.details && detailsString) {
  layers[layerMap.details] = { text: detailsString };
}
layerMap.images.forEach((slotName, i) => {
  if (imageUrls[i]) {
    layers[slotName] = { image_url: imageUrls[i] };
  } else {
    layers[slotName] = { hide: true };
  }
});

return [
  {
    json: {
      notionPageId: item.id,
      templateId,
      nextCounter,
      postType,
      detailsString,
      layers,
      itemName: item["Item Name"] || "",
      renderName: `AA_${postType}_${(item.id || "item").slice(0, 8)}`,
    },
  },
];

const raw = $input.first().json.choices[0].message.content;

// Split on the delimiter
const parts = raw.split("|||HERO|||");
const caption = (parts[0] || "").trim();
const hero   = (parts[1] || "").trim();

// ── Get Notion data from Get Many node (new key format) ──────────
const notionRaw = $('Get Many - Ready Items').first().json;
// (replace 'Get Many - Ready Items' with whatever you named that node)

const detailsType = notionRaw.property_details_type || "single_item";
const condition   = notionRaw.property_condition    || "";
const price       = notionRaw.property_price
  ? `PHP ${Number(notionRaw.property_price).toLocaleString()}`
  : "";

// ── Details string composer ───────────────────────────────────────
let detailsString = "";
switch (detailsType) {
  case "single_item":
    detailsString = [condition, price].filter(Boolean).join(" · ");
    break;
  case "multi_item":
    detailsString = "Multiple pieces · DM for prices";
    break;
  case "price_range":
    detailsString = price ? `Starting ${price}` : "Starting price — DM to ask";
    break;
  case "category_drop":
    detailsString = "Fresh arrivals · Stocks vary";
    break;
  case "arrival_teaser":
    detailsString = "Sorting now · Watch this page";
    break;
}

return [{
  json: {
    generatedCaption: caption,
    heroLine:         hero,
    detailsString:    detailsString,
    notionPageId:     notionRaw.id,  // carry the page ID forward for write-back
  }
}];

const callbackData = $input.first().json.callback_query.data;
const chatId = $input.first().json.callback_query.from.id;
const messageId = $input.first().json.callback_query.message.message_id;

// Split "approve__37fdabb9-..." into ["approve", "37fdabb9-..."]
const [action, notionPageId] = callbackData.split("__");

return [{
  json: {
    action,           // "approve" or "reject"
    notionPageId,     // the Notion page ID
    chatId,           // for sending confirmation back
    messageId,        // for editing the original message later
  }
}];

const now = new Date();
const manila = new Date(now.toLocaleString("en-US", { timeZone: "Asia/Manila" }));
const hour = manila.getHours();
const minute = manila.getMinutes();

const slots = [9, 12, 20]; // 9am, 12pm, 8pm

// Find next slot strictly after current time
let targetHour = slots.find(h => h > hour || (h === hour && minute === 0));
let targetDate = new Date(manila);

if (!targetHour) {
  // All slots passed today — schedule for 9am tomorrow
  targetHour = 9;
  targetDate.setDate(targetDate.getDate() + 1);
}

targetDate.setHours(targetHour, 0, 0, 0);

// Buffer expects UTC Unix timestamp
// Manila is UTC+8
const utcTimestamp = Math.floor(targetDate.getTime() / 1000) - (8 * 3600);

const readableTime = targetDate.toLocaleString("en-PH", {
  timeZone: "Asia/Manila",
  dateStyle: "medium",
  timeStyle: "short"
});

return [{
  json: {
    ...($input.first().json),   // carry notionPageId + chatId forward
    scheduledAt: utcTimestamp,
    readableTime,
  }
}];
